from typing import List

def move_zeroes(nums: List[int]) -> None:
    non_zero_idx = 0
    for val in nums:
        if val != 0:
            nums[non_zero_idx] = val
            non_zero_idx += 1
    for i in range(non_zero_idx, len(nums)):
        nums[i] = 0
